// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.28;

import {Err} from "./../../lib/Errors.sol";
import {LogExpMath} from "./../../lib/math/LogExpMath.sol";
import {PMath} from "./../../lib/math/PMath.sol";

struct AMMState {
    /// abstract world
    uint256 totalFloatAmount;
    uint256 normFixedAmount;
    /// real world
    uint256 totalLp;
    /// market data
    uint256 latestFTime;
    /// immutable variables
    uint256 maturity;
    uint256 seedTime;
    /// config
    uint256 minAbsRate;
    uint256 maxAbsRate;
    uint256 cutOffTimestamp;
}

struct AMMSeedParams {
    uint256 minAbsRate;
    uint256 maxAbsRate;
    uint256 cutOffTimestamp;
    uint256 initialAbsRate;
    int256 initialSize;
    uint256 flipLiquidity;
    uint256 initialCash;
}

library PositiveAMMMath {
    using PMath for uint256;
    using PMath for int256;
    using LogExpMath for uint256;

    uint256 internal constant RATE_EPS = 10;

    function calcSeedOutput(
        AMMSeedParams memory params,
        uint256 maturity,
        uint256 latestFTime
    ) internal pure returns (AMMState memory initialState) {
        uint256 totalFloatAmount = (params.initialSize + params.flipLiquidity.Int()).Uint();
        uint256 normFixedAmount = totalFloatAmount.mulDown(params.initialAbsRate);
        uint256 liquidity = (totalFloatAmount * normFixedAmount).sqrt();

        uint256 fixedValue = (normFixedAmount * (maturity - latestFTime)) / 365 days;
        require(params.initialCash > fixedValue, Err.AMMInsufficientCashIn());

        initialState = AMMState({
            totalFloatAmount: totalFloatAmount,
            normFixedAmount: normFixedAmount,
            totalLp: liquidity,
            latestFTime: latestFTime,
            maturity: maturity,
            seedTime: latestFTime,
            minAbsRate: params.minAbsRate,
            maxAbsRate: params.maxAbsRate,
            cutOffTimestamp: params.cutOffTimestamp
        });
    }

    function calcMintOutput(
        AMMState memory state,
        int256 markRate,
        int256 totalCash,
        int256 _totalSize,
        int256 maxCashIn,
        int256 exactSizeIn
    ) internal pure returns (int256 netCashIn, uint256 netLpOut) {
        bool isMatured = state.maturity <= state.latestFTime;
        require(!isMatured, Err.MarketMatured());

        assert(totalCash > 0);

        int256 totalSize = _snapSmallSizeTo0(_totalSize);

        // This also applies to sign() == 0
        require(totalSize.sign() == exactSizeIn.sign(), Err.AMMSignMismatch());

        if (totalSize == 0) {
            netLpOut = (state.totalLp * maxCashIn.Uint()) / uint256(totalCash);
            netCashIn = maxCashIn;
        } else {
            uint256 absTotalSize = totalSize.abs();
            uint256 absExactSizeIn = exactSizeIn.abs();

            bool isPositionValuePositive = totalSize.sign() == markRate.sign();
            if (isPositionValuePositive) {
                netLpOut = (state.totalLp * absExactSizeIn) / absTotalSize;
            } else {
                netLpOut = (state.totalLp * absExactSizeIn).rawDivUp(absTotalSize);
            }

            netCashIn = (uint256(totalCash) * netLpOut).rawDivUp(state.totalLp).Int();

            require(netCashIn <= maxCashIn, Err.AMMInsufficientCashIn());
        }

        state.totalFloatAmount += (state.totalFloatAmount * netLpOut) / state.totalLp;
        state.normFixedAmount += (state.normFixedAmount * netLpOut) / state.totalLp;
        state.totalLp += netLpOut;
    }

    function calcBurnOutput(
        AMMState memory state,
        int256 markRate,
        int256 totalCash,
        int256 _totalSize,
        uint256 lpToBurn
    ) internal pure returns (int256 netCashOut, int256 netSizeOut, bool isMatured) {
        netCashOut = (totalCash * lpToBurn.Int()) / state.totalLp.Int();

        isMatured = state.maturity <= state.latestFTime;
        if (isMatured) {
            return (netCashOut, 0, isMatured);
        }

        int256 totalSize = _snapSmallSizeTo0(_totalSize);
        uint256 absSizeOut;
        bool isPositionValuePositive = totalSize.sign() == markRate.sign();
        if (isPositionValuePositive) {
            absSizeOut = (totalSize.abs() * lpToBurn) / state.totalLp;
        } else {
            absSizeOut = (totalSize.abs() * lpToBurn).rawDivUp(state.totalLp);
        }
        netSizeOut = absSizeOut.Int() * totalSize.sign();

        state.totalFloatAmount -= (state.totalFloatAmount * lpToBurn) / state.totalLp;
        state.normFixedAmount -= (state.normFixedAmount * lpToBurn) / state.totalLp;
        state.totalLp -= lpToBurn;
    }

    function calcSwapOutput(AMMState memory state, int256 floatOut) internal pure returns (int256 fixedIn) {
        uint256 normalizedTime = calcNormalizedTime(state);

        uint256 newTotalFloatAmount;
        uint256 floatOutAbs = floatOut.abs();
        if (floatOut > 0) {
            // totalFloatAmount.pow(normalizedTime) does not work when totalFloatAmount = 1
            require(state.totalFloatAmount > floatOutAbs + 1, Err.AMMInsufficientLiquidity());
            unchecked {
                newTotalFloatAmount = state.totalFloatAmount - floatOutAbs;
            }
        } else {
            newTotalFloatAmount = state.totalFloatAmount + floatOutAbs;
        }

        uint256 liquidity = state.totalFloatAmount.pow(normalizedTime).mulDown(state.normFixedAmount);
        uint256 newNormFixedAmount = liquidity.divDown(newTotalFloatAmount.pow(normalizedTime));
        require(
            newNormFixedAmount * PMath.ONE >= state.minAbsRate * newTotalFloatAmount,
            Err.AMMInsufficientLiquidity()
        );
        require(
            newNormFixedAmount * PMath.ONE <= state.maxAbsRate * newTotalFloatAmount,
            Err.AMMInsufficientLiquidity()
        );
        int256 normFixedIn = newNormFixedAmount.Int() - state.normFixedAmount.Int();

        state.totalFloatAmount = newTotalFloatAmount;
        state.normFixedAmount = newNormFixedAmount;

        return normFixedIn.divDown(normalizedTime.Int());
    }

    function calcSwapSize(AMMState memory state, int256 targetRateInt) internal pure returns (int256 swapSize) {
        int256 currentRate = calcImpliedRate(state.totalFloatAmount, state.normFixedAmount);
        if ((targetRateInt - currentRate).abs() < RATE_EPS || isCutOffReached(state)) {
            return 0;
        }

        uint256 targetRate = clampRate(state, targetRateInt).Uint();
        uint256 normalizedTime = calcNormalizedTime(state);
        uint256 normalizedTimePlusOne = normalizedTime + PMath.ONE;
        uint256 liquidityMul1E18 = state.totalFloatAmount.pow(normalizedTime) * state.normFixedAmount;
        uint256 newTotalFloatAmount = (liquidityMul1E18 / targetRate).pow(PMath.ONE.divDown(normalizedTimePlusOne)).max(
            2
        );
        swapSize = state.totalFloatAmount.Int() - newTotalFloatAmount.Int();
    }

    function clampRate(AMMState memory state, int256 rate) internal pure returns (int256) {
        (uint256 adjustedMinAbsRate, uint256 adjustedMaxAbsRate) = tweakRate(state.minAbsRate, state.maxAbsRate);
        return rate.max(adjustedMinAbsRate.Int()).min(adjustedMaxAbsRate.Int());
    }

    uint256 internal constant RATE_TWEAK_FACTOR = 1e8;
    function tweakRate(
        uint256 minAbsRate,
        uint256 maxAbsRate
    ) internal pure returns (uint256 adjustedMinAbsRate, uint256 adjustedMaxAbsRate) {
        adjustedMinAbsRate = minAbsRate.tweakUp(RATE_TWEAK_FACTOR);
        adjustedMaxAbsRate = maxAbsRate.tweakDown(RATE_TWEAK_FACTOR);
    }

    function calcImpliedRate(uint256 totalFloatAmount, uint256 normFixedAmount) internal pure returns (int256) {
        return normFixedAmount.divDown(totalFloatAmount).Int();
    }

    function calcNormalizedTime(AMMState memory state) internal pure returns (uint256) {
        require(!isCutOffReached(state), Err.AMMCutOffReached());
        return (state.maturity - state.latestFTime).divDown(state.maturity - state.seedTime);
    }

    function isCutOffReached(AMMState memory state) internal pure returns (bool) {
        return state.latestFTime >= state.cutOffTimestamp;
    }

    function _snapSmallSizeTo0(int256 size) internal pure returns (int256) {
        return size.abs() < 1e3 ? int256(0) : size;
    }
}

contracts/core/contracts/core/router/mat.content:
// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.28;

import {Err} from "./../../../lib/Errors.sol";
import {PMath} from "./../../../lib/math/PMath.sol";
import {TickMath} from "./../../../lib/math/TickMath.sol";
import {MarketAcc} from "./../../../types/Account.sol";
import {Side, SideLib} from "./../../../types/Order.sol";
import {TickSweepState, TickSweepStateLib, Stage} from "./TickSweepStateLib.sol";
import {IMarket} from "./../../../interfaces/IMarket.sol";
import {IAMM} from "./../../../interfaces/IAMM.sol";
import {PaymentLib} from "./../../../lib/PaymentLib.sol";

struct SwapMathParams {
    address market;
    MarketAcc user;
    MarketAcc amm;
    Side userSide;
    uint256 takerFeeRate;
    uint256 ammOtcFeeRate;
    uint256 ammAllInFeeRate;
    uint8 tickStep;
    uint16 nTicksToTryAtOnce;
    uint32 timeToMat;
}

using SwapMathLib for SwapMathParams global;
using SwapMathHighLevelLib for SwapMathParams global;

library SwapMathLib {
    using PMath for uint256;
    using PMath for int256;
    using SideLib for int256;
    using TickMath for int16;

    function create(
        address market_,
        uint8 tickStep,
        uint16 nTicksToTryAtOnce,
        MarketAcc user_,
        MarketAcc amm_,
        Side userSide,
        uint32 timeToMat
    ) internal view returns (SwapMathParams memory params) {
        if (amm_.isZero()) return params;

        require(timeToMat > 0, Err.MarketMatured());

        (uint256 takerFeeRate, uint256 ammOtcFeeRate) = IMarket(market_).getBestFeeRates(user_, amm_);

        return
            SwapMathParams({
                market: market_,
                user: user_,
                amm: amm_,
                userSide: userSide,
                takerFeeRate: takerFeeRate,
                ammOtcFeeRate: ammOtcFeeRate,
                ammAllInFeeRate: ammOtcFeeRate + IAMM(amm_.root()).feeRate(),
                tickStep: tickStep,
                nTicksToTryAtOnce: nTicksToTryAtOnce,
                timeToMat: timeToMat
            });
    }

    /// @notice Swaps as much as possible with AMM as long as its implied rate
    /// is better than the fee-adjusted rate corresponding to bookTick,
    /// pushing AMM rate to (but not necessary ending up at) that adjusted rate.
    /// Returns 0 when AMM is not swappable (e.g. after cutoff, AMM is withdraw-only).
    /// @dev See docs for IAMM.calcSwapSize
    function calcSwapAMMToBookTick(
        SwapMathParams memory self,
        int16 bookTick
    ) internal view returns (int256 /*swapSize*/) {
        int256 baseRate = convertBookTickToBaseRate(self, bookTick);
        int256 ammRate = convertBaseRateToAMMRate(self, baseRate);
        int256 swapSize = IAMM(self.amm.root()).calcSwapSize(ammRate);
        return swapSize.isOfSide(self.userSide) ? swapSize : int256(0);
    }

    function calcAmmOtcFee(SwapMathParams memory self, int256 swapSize) internal pure returns (uint256 /*fee*/) {
        return PaymentLib.calcFloatingFee(swapSize.abs(), self.ammOtcFeeRate, self.timeToMat);
    }

    function calcBookTakerFee(SwapMathParams memory self, int256 swapSize) internal pure returns (uint256 /*fee*/) {
        return PaymentLib.calcFloatingFee(swapSize.abs(), self.takerFeeRate, self.timeToMat);
    }

    function calcSwapAMM(
        SwapMathParams memory self,
        int256 ammSwapSize
    ) internal view returns (int256 netCashIn, int256 netCashToAMM) {
        if (ammSwapSize == 0) return (0, 0);
        int256 ammCost = IAMM(self.amm.root()).swapView(ammSwapSize);
        netCashToAMM = PaymentLib.calcUpfrontFixedCost(ammCost, self.timeToMat);
        netCashIn = netCashToAMM + self.calcAmmOtcFee(ammSwapSize).Int();
    }

    function calcSwapBook(
        SwapMathParams memory self,
        int256 bookSwapSize,
        int256 bookCost
    ) internal pure returns (int256 /*netCashIn*/) {
        return PaymentLib.calcUpfrontFixedCost(bookCost, self.timeToMat) + self.calcBookTakerFee(bookSwapSize).Int();
    }

    function convertBookTickToBaseRate(SwapMathParams memory self, int16 bookTick) internal pure returns (int256) {
        int256 bookRate = bookTick.getRateAtTick(self.tickStep);
        return self.userSide == Side.LONG ? bookRate + int256(self.takerFeeRate) : bookRate - int256(self.takerFeeRate);
    }

    function convertBaseRateToAMMRate(SwapMathParams memory self, int256 baseRate) private pure returns (int256) {
        return
            self.userSide == Side.LONG
                ? baseRate - int256(self.ammAllInFeeRate)
                : baseRate + int256(self.ammAllInFeeRate);
    }
}

library SwapMathHighLevelLib {
    using PMath for uint256;
    using PMath for int256;
    using SideLib for uint256;

    /**
     * sweepState starts with either swept_all or loop_batch
     * it breaks when either swept_all or found_stop
     * For transition up, single & binary moves the iterator, batch to either swept_all or found_stop or continue batch
     * For transition down, single & binary moves the iterator, batch to either swept_all or found_stop or continue batch
     */
    function calcSwapAmountBookAMM(
        SwapMathParams memory $,
        int256 totalSize,
        int16 limitTick
    ) internal view returns (int256 withBook, int256 withAMM) {
        if ($.amm.isZero() || totalSize == 0) return (0, 0);

        Side matchingSide = $.userSide.opposite();
        TickSweepState memory sweep = TickSweepStateLib.create($.market, matchingSide, $.nTicksToTryAtOnce);

        while (sweep.hasMore()) {
            (int16 lastTick, uint256 sumTickSize) = sweep.getLastTickAndSumSize();
            if (!matchingSide.canMatch(limitTick, lastTick)) {
                sweep.transitionDown();
                continue;
            }

            int256 tmpWithAMM = $.calcSwapAMMToBookTick(lastTick);
            int256 tmpWithBook = withBook + sumTickSize.toSignedSize($.userSide);
            int256 newTotalSize = tmpWithBook + tmpWithAMM;

            if (newTotalSize == totalSize) return (tmpWithBook, tmpWithAMM);
            if (newTotalSize.abs() > totalSize.abs()) sweep.transitionDown();
            else {
                withBook = tmpWithBook;
                sweep.transitionUp();
            }
        }

        return _calcFinalSwapAmount($, sweep, withBook, totalSize, limitTick);
    }

    function _calcFinalSwapAmount(
        SwapMathParams memory $,
        TickSweepState memory sweepState,
        int256 withBook,
        int256 totalSize,
        int16 limitTick
    ) private view returns (int256, int256) {
        int16 finalTick = _getFinalTick($, sweepState, limitTick);
        int256 maxWithAMM = $.calcSwapAMMToBookTick(finalTick);
        int256 withAMM = PMath.min((totalSize - withBook).abs(), maxWithAMM.abs()).toSignedSize($.userSide);
        return (totalSize - withAMM, withAMM);
    }

    function _getFinalTick(
        SwapMathParams memory $,
        TickSweepState memory sweepState,
        int16 limitTick
    ) private pure returns (int16 finalTick) {
        if (sweepState.stage == Stage.FOUND_STOP) {
            int16 lastTick = sweepState.getLastTick();
            Side matchingSide = $.userSide.opposite();
            return matchingSide.canMatch(limitTick, lastTick) ? lastTick : limitTick;
        } else if (sweepState.stage == Stage.SWEPT_ALL) {
            return limitTick;
        }
        assert(false);
    }
}

